update products set description = 'Die Starthilfe Powerbank liefert 7000 Ampere Spitzenstrom — genug, um die meisten Benzin- und Dieselmotoren bis 8,5 Liter Hubraum zu starten. Gleichzeitig lädt sie Smartphones per USB-C oder USB-A. Kompakter als eine Starthilfekabel-Verbindung zu einem anderen Auto und deutlich zuverlässiger, wenn man alleine auf einem Parkplatz steht.' where slug = 'starthilfe-powerbank-7000a-booster';

update products set description = 'Das JOYROOM Kabelmanagement klebt selbstklebend unter den Schreibtisch oder an die Wand und hält Ladekabel, HDMI-Kabel und USB-Hubs in Griffweite, ohne dass sie sichtbar herumbaumeln. Die Klemmen lassen sich ohne Werkzeug öffnen und wieder schließen. Sauberer Schreibtisch in 10 Minuten — das ist kein Versprechen, das ist Physik.' where slug = 'joyroom-kabelmanagement-schreibtisch-selbstklebend';

