update products set description = 'Das personalisierte LED-Leuchtschild wird individuell mit Name, Wort oder Phrase graviert und strahlt in warmweißem oder farbigem Licht. Die Acrylglas-Scheibe steht auf einem USB-betriebenen Sockel — einfach einstecken und leuchten lassen. Als Geschenk, Zimmer-Deko oder Bar-Schild kaum zu schlagen, weil es tatsächlich so aussieht wie etwas, das man sich selbst kaufen würde.' where slug = 'personalisiertes-leuchtschild-wanddekoration';

