update products set description = 'Das FENTEC schwebende Bücherregal wird mit versteckten Wandträgern montiert — von vorne sieht es aus, als würden Bücher frei in der Luft stehen. Belastbar bis 5 kg pro Regal, einfach zu montieren, keine sichtbaren Schrauben. Wer Bücher liebt und eine leere Wand hat, sollte dieses Regal kaufen, bevor jemand anderes darauf kommt.' where slug = 'fentec-schwebendes-buecherregal';

